import React, { useState, useEffect } from "react";
import axios from "axios";


const Payments = () => {
  const [bookings, setBookings] = useState([]);
  const [selectedBooking, setSelectedBooking] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("card");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        setLoading(true);
        const res = await axios.get("http://localhost:5000/api/bookings/my", {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        const unpaidBookings = res.data.bookings.filter(
          (b) => b.paymentStatus !== "paid" && b.status !== "cancelled"
        );
        setBookings(unpaidBookings);
      } catch (error) {
        console.error(error);
        setMessage("Failed to load bookings.");
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, [user.token]);

  const handlePayment = async () => {
    if (!selectedBooking) {
      setMessage("Please select a booking to pay.");
      return;
    }

    try {
      setLoading(true);
      const res = await axios.post(
        "http://localhost:5000/api/payments",
        { bookingId: selectedBooking, paymentMethod },
        { headers: { Authorization: `Bearer ${user.token}` } }
      );

      setMessage("Payment successful!");
      // Remove paid booking from list
      setBookings(bookings.filter((b) => b._id !== selectedBooking));
      setSelectedBooking("");
    } catch (error) {
      console.error(error);
      setMessage(
        error.response?.data?.message || "Payment failed. Try again."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="payments-page">
      <h1>Make Payment</h1>

      {message && <div className="message">{message}</div>}

      {loading && <p>Loading...</p>}

      {bookings.length === 0 && !loading && (
        <p>No pending bookings available for payment.</p>
      )}

      {bookings.length > 0 && (
        <div className="payment-form">
          <label htmlFor="booking">Select Booking:</label>
          <select
            id="booking"
            value={selectedBooking}
            onChange={(e) => setSelectedBooking(e.target.value)}
          >
            <option value="">-- Select --</option>
            {bookings.map((b) => (
              <option key={b._id} value={b._id}>
                {b.event.name} | Tickets: {b.numberOfTickets} | Amount: $
                {b.totalAmount}
              </option>
            ))}
          </select>

          <label htmlFor="paymentMethod">Payment Method:</label>
          <select
            id="paymentMethod"
            value={paymentMethod}
            onChange={(e) => setPaymentMethod(e.target.value)}
          >
            <option value="card">Card</option>
            <option value="upi">UPI</option>
            <option value="netbanking">Net Banking</option>
            <option value="wallet">Wallet</option>
          </select>

          <button onClick={handlePayment} disabled={loading}>
            Pay Now
          </button>
        </div>
      )}
    </div>
  );
};

export default Payments;
